mapper.insert:
		/*
             SQL ID : SrvyVwitmDAO.srvyVwitmBulkRegist
             설  명 : 설문보기항목일괄등록
         */
         INSERT ALL

			INTO TB_LMS_SRVY_VWITM (
	         	  SRVY_VWITM_ID
				, SRVY_QSTN_ID
				, VWITM_GBNCD
				, VWITM_CTS
				, VWITM_SEQNO
				, MVMN_SRVY_QSTN_ID
				, ETC_INPTYN
				, RGTR_ID
				, REG_DTTM
	         ) VALUES (
	         	  #{item.srvyVwitmId}
				, #{item.srvyQstnId}
				, #{item.vwitmGbncd}
				, #{item.vwitmCts}
				, #{item.vwitmSeqno}
				, #{item.mvmnSrvyQstnId}
				, #{item.etcInptyn}
				, #{item.rgtrId}
				, FN_DTTM()
	         )

		SELECT * FROM DUAL

mapper.delete:
		/*
             SQL ID : SrvyVwitmDAO.srvyVwitmDelete
             설  명 : 설문보기항목삭제
         */
        DELETE FROM TB_LMS_SRVY_VWITM
         WHERE SRVY_QSTN_ID = #{srvyQstnId}
